class CommentViewSet(ViewSet):
    def list(self, request, pub_id):
        comments = Comment.objects.filter(publication_id=pub_id, is_deleted=False)
        tree = self.build_tree(comments)
        return Response(tree)

    def create(self, request, pub_id):
        content = request.data.get('content')
        parent_id = request.data.get('parent_id')

        if len(content) < 10:
            return Response({'error': 'Too short'}, status=400)

        if self.is_spam(request.user.id, content):
            return Response({'error': 'Spam detected'}, status=403)

        comment = Comment.objects.create(
            publication_id=pub_id,
            user_id=request.user.id,
            content=content,
            parent_id=parent_id
        )

        return Response(self.serialize(comment))

    def build_tree(self, comments):
        comment_dict = {c.id: self.serialize(c) for c in comments}
        tree = []

        for c in comments:
            if c.parent_id is None:
                tree.append(comment_dict[c.id])
            else:
                if c.parent_id in comment_dict:
                    if 'replies' not in comment_dict[c.parent_id]:
                        comment_dict[c.parent_id]['replies'] = []
                    comment_dict[c.parent_id]['replies'].append(comment_dict[c.id])

        return tree
