class ComponentLibraryManager {
  async saveComponent(
    name: string,
    category: string,
    grapesComponent: any
  ): Promise<ComponentTemplate> {
    // Generate thumbnail
    const thumbnail = await generateThumbnail(grapesComponent);
    
    // Save to database
    const template: ComponentTemplate = {
      id: uuidv4(),
      name,
      category,
      thumbnail,
      grapesData: grapesComponent.toJSON(),
      createdAt: new Date(),
      updatedAt: new Date(),
      isGlobal: false
    };
    
