<script>
import draggable from 'vuedraggable';
import DealCard from './DealCard.vue';

export default {
  components: { draggable, DealCard },
  
  data() {
    return {
      stages: []
    };
  },
  
  async created() {
    await this.loadPipeline();
  },
  
  methods: {
    async loadPipeline() {
      const response = await this.$api.get('/deals/pipeline');
      this.stages = response.data;
    },
    
    async handleDealMove(stageId, event) {
      if (event.added) {
        const deal = event.added.element;
        await this.$api.put(`/deals/${deal.id}`, {
          stageId: stageId
        });
        
        // Show success notification
        this.$notify.success('Deal moved successfully');
        
        // Update deal history
        await this.logDealActivity(deal.id, 'stage_changed', stageId);
      }
    },
    
    showDealDetail(deal) {
      this.$router.push(`/deals/${deal.id}`);
    }
  }
};
</script>
